    p = sub.add_parser('self-fill-gap-scan', help='Scan the graph for missing surfaces and stage self-fill candidates.'); p.add_argument('--language-id', action='append', default=[]); p.add_argument('--no-stage', action='store_true')
    p = sub.add_parser('list-self-fill-candidates', help='List staged self-fill candidates.'); p.add_argument('--status'); p.add_argument('--language-id'); p.add_argument('--surface-type'); p.add_argument('--limit', type=int, default=200)
    p = sub.add_parser('list-self-fill-scans', help='List self-fill scan runs.'); p.add_argument('--limit', type=int, default=50)
    p = sub.add_parser('promote-self-fill-candidate', help='Promote a staged self-fill candidate into canonical truth.'); p.add_argument('candidate_id'); p.add_argument('--reviewer', default='autofill_promoter')
    p = sub.add_parser('reject-self-fill-candidate', help='Reject a staged self-fill candidate.'); p.add_argument('candidate_id'); p.add_argument('--reviewer', default='autofill_reviewer'); p.add_argument('--notes', default='')


