    p = sub.add_parser('arbitrate-self-fill-candidates', help='Score and rank competing self-fill candidates by source authority and confidence.'); p.add_argument('--language-id'); p.add_argument('--min-score', type=float, default=0.35)
    p = sub.add_parser('list-self-fill-arbitration-runs', help='List self-fill arbitration runs.'); p.add_argument('--limit', type=int, default=50)
    p = sub.add_parser('list-self-fill-arbitration-decisions', help='List self-fill arbitration decisions.'); p.add_argument('--arbitration-run-id'); p.add_argument('--limit', type=int, default=100)
    p = sub.add_parser('promote-arbitrated-self-fill', help='Auto-promote arbitration winners above threshold.'); p.add_argument('--language-id'); p.add_argument('--min-score', type=float, default=0.35); p.add_argument('--reviewer', default='autofill_arbiter')
    p = sub.add_parser('recommend-source-weight', help='Write or update a source authority weight for self-fill arbitration.'); p.add_argument('source_name'); p.add_argument('authority_weight', type=float); p.add_argument('--notes', default='self-fill arbitration override')
    p = sub.add_parser('run-recurring-self-fill-release', help='Run the governed recurring self-fill release pipeline.'); p.add_argument('--min-score', type=float, default=0.35); p.add_argument('--reviewer', default='self_fill_release_pipeline'); p.add_argument('--signing-key')
    p = sub.add_parser('list-self-fill-release-runs', help='List self-fill release runs.'); p.add_argument('--limit', type=int, default=50)
    p = sub.add_parser('list-self-fill-release-artifacts', help='List self-fill release artifacts.'); p.add_argument('--release-run-id'); p.add_argument('--limit', type=int, default=100)
    p = sub.add_parser('run-scheduled-self-fill-release', help='Run the scheduled self-fill release cycle with retention and rollback indexing.'); p.add_argument('--schedule-kind', default='daily'); p.add_argument('--min-score', type=float, default=0.35); p.add_argument('--reviewer', default='self_fill_release_pipeline'); p.add_argument('--signing-key')
    p = sub.add_parser('list-self-fill-retention-policies', help='List enabled self-fill retention policies.'); p.add_argument('--limit', type=int, default=50)
    p = sub.add_parser('list-self-fill-retention-actions', help='List self-fill retention actions.'); p.add_argument('--limit', type=int, default=100)
    p = sub.add_parser('list-self-fill-rollback-index', help='List replayable self-fill rollback index entries.'); p.add_argument('--limit', type=int, default=100)

    p = sub.add_parser('build-self-fill-replay-manifest', help='Build a replay manifest for a rollback-indexed release.'); p.add_argument('--rollback-id'); p.add_argument('--release-run-id')
    p = sub.add_parser('restore-self-fill-snapshot', help='Restore the canonical SQLite DB from a rollback-indexed release snapshot.'); p.add_argument('--rollback-id'); p.add_argument('--release-run-id'); p.add_argument('--no-backup', action='store_true')
    p = sub.add_parser('compact-self-fill-release', help='Create a compact archive bundle for a rollback-indexed release.'); p.add_argument('--rollback-id'); p.add_argument('--release-run-id')
    p = sub.add_parser('list-self-fill-replay-runs', help='List prepared self-fill replay manifests.'); p.add_argument('--limit', type=int, default=100)
    p = sub.add_parser('list-self-fill-compaction-actions', help='List self-fill compaction actions.'); p.add_argument('--limit', type=int, default=100)

    # Acquisition workspace
    p = sub.add_parser('plan-acquisition-job', help='Plan a corpus acquisition job for a named corpus manifest.'); p.add_argument('corpus_name'); p.add_argument('--stage-name', default='staging'); p.add_argument('--output-dir'); p.add_argument('--notes', default='')
    p = sub.add_parser('record-staged-asset', help='Record a staged asset file for an acquisition job.'); p.add_argument('job_id'); p.add_argument('file_path'); p.add_argument('--asset-kind', default='unknown'); p.add_argument('--notes', default='')
